func mapBadge(mode string) string {
	if mode == "procedural" {
		return "info"
	}
	return "accent"
}

func mapThumbLabel(m maps.Map) string {
	return fmt.Sprintf("%d × %d", m.Width, m.Height)
}

// mapFilterLabel turns the ?filter= scope into a chip label.
func mapFilterLabel(f string) string {
	switch f {
	case "empty":
		return "no entities placed"
	default:
		return f
	}
}

func countMapMode(items []maps.Map, mode string) int {
	n := 0
	for _, m := range items {
		if m.Mode == mode {
			n++
		}
	}
	return n
}

